// 生成运行 ID
const runId = Date.now().toString(36) + '-' + Math.random().toString(36).substring(2, 8);
const startTime = new Date().toISOString();

return [{
  json: {
    runId: runId,
    startTime: startTime,
    status: 'started',
    input: {
      title: $input.body?.title || '',
      content: $input.body?.content || ''
    }
  }
}];

// 处理 Ollama 调用失败
const runId = $input.first().json.runId;
const error = $json.error || '未知错误';
const title = $input.first().json.title || '未知';
const timestamp = new Date().toISOString();

const failureLog = {
  runId: runId,
  step: 'call-ollama',
  error: error,
  title: title,
  timestamp: timestamp,
  status: 'failed',
  needsReview: True
};

return [{
  json: failureLog
}];

// 解析 Ollama 返回的文本
const response = $input.first().json.response;

// 辅助函数
function extractSection(text, marker) {
  const regex = new RegExp(marker + '([\s\S]*?)(?=【|$)');
  const match = text.match(regex);
  return match ? match[1].trim() : '';
}

function extractScore(text, layer) {
  // 兼容中英文冒号、全半角空格
  const regex = new RegExp(layer + '[：:]\\s*(\\d+)\\s*/\\s*10');
  const match = text.match(regex);
  return match ? parseInt(match[1]) : 0;
}

function extractList(text, marker) {
  const section = extractSection(text, marker);
  return section
    .split('\n')
    .map(line => line.trim())
    .filter(line => /^\d+[.．、]/.test(line))
    .map(line => line.replace(/^\d+[.．、]\s*/, '').trim())
    .filter(item => item.length > 0);
}

function extractPlatforms(text) {
  const section = extractSection(text, '【推荐平台】');
  const lines = section
    .split('\n')
    .map(line => line.trim())
    .filter(line => /^\d+[.．、]/.test(line));

  return lines.map(line => {
    const match = line.match(/^\d+[.．、]\s*(.+?)[（(](.+?)[)）]/);
    if (match) {
      return { name: match[1].trim(), reason: match[2].trim() };
    }
    const nameMatch = line.match(/^\d+[.．、]\s*(.+)/);
    return { name: nameMatch ? nameMatch[1].trim() : line, reason: '' };
  });
}

function extractRewrite(text) {
  const section = extractSection(text, '【改写建议】');
  const result = {};

  const patterns = [
    ['title', /标题优化[：:]\s*([\s\S]*?)(?=开头优化|$)/],
    ['hook', /开头优化[：:]\s*([\s\S]*?)(?=正文优化|$)/],
    ['body', /正文优化[：:]\s*([\s\S]*?)(?=结尾优化|$)/],
    ['ending', /结尾优化[：:]\s*([\s\S]*?)(?=【|$)/]
  ];
  for (const [key, pat] of patterns) {
    const m = section.match(pat);
    result[key] = m ? m[1].trim() : '';
  }
  return result;
}

function extractPlatformAdaptation(text) {
  const section = extractSection(text, '【平台适配】');
  const result = {};
  const lines = section.split('\n');
  for (const line of lines) {
    const match = line.match(/^([^：:]+)[：:]\s*(.+)$/);
    if (match) {
      result[match[1].trim()] = match[2].trim();
    }
  }
  return result;
}

// 主解析
const primaryMatch = response.match(/【主要类型】(.+?)\n/);
const primaryRaw = primaryMatch ? primaryMatch[1].trim() : '';
const layerTypeMatch = primaryRaw.match(/(.+?)层\s*[-—]\s*(.+)/);

const primaryLayer = layerTypeMatch ? layerTypeMatch[1].trim() : primaryRaw;
const primaryType = layerTypeMatch ? layerTypeMatch[2].trim() : '';

const result = {
  primaryLayer: primaryLayer,
  primaryType: primaryType,
  scores: {
    traffic: extractScore(response, '流量层'),
    understanding: extractScore(response, '理解层'),
    connection: extractScore(response, '连接层'),
    packaging: extractScore(response, '包装层'),
    conversion: extractScore(response, '转化层')
  },
  characteristics: extractList(response, '【内容特征】'),
  suggestions: extractList(response, '【策略建议】'),
  optimizationTips: extractList(response, '【优化建议】'),
  recommendedPlatforms: extractPlatforms(response),
  rewrite: extractRewrite(response),
  platformAdaptation: extractPlatformAdaptation(response),
  rawResponse: response
};

return [{ json: result }];

// 记录成功运行日志
const runId = $input.first().json.runId;
const endTime = new Date().toISOString();

const successLog = {
  runId: runId,
  endTime: endTime,
  status: 'success',
  timestamp: endTime
};

return [{
  json: successLog
}];
